(() => {
    type UnionC = Date | number | string | {a?: UnionC; b?: string} | UnionC[];
    return {build: () => createValidate<UnionC>(), buildErrors: () => noErrs(createGetValidationErrors<UnionC>())};
  })()

() => {
    const uc = RT.circular((self) =>
      RT.union([
        RT.date(),
        RT.number(),
        RT.string(),
        RT.object({a: RT.optional(self), b: RT.optional(RT.string())}),
        RT.array(self),
      ])
    );
    return createValidate(uc);
  }

{
    build: () => {
      type UnionC = Date | number | string | {a?: UnionC; b?: string} | UnionC[];
      const check = typia.createIs<UnionC>();
      return (v) => check(v);
    },
    buildErrors: () => {
      type UnionC = Date | number | string | {a?: UnionC; b?: string} | UnionC[];
      const val = typia.createValidate<UnionC>();
      return (v) => val(v).success;
    },
    samples: {invalid: [true, null, undefined, {a: true}, [true], Symbol()]},
  }

c(z.lazy(() => {
    const check = (v: unknown): boolean => {
      if (v instanceof Date) return !isNaN(v.getTime());
      if (typeof v === 'number') return Number.isFinite(v);
      if (typeof v === 'string') return true;
      if (Array.isArray(v)) return v.every(check);
      if (typeof v === 'object' && v !== null && !(v instanceof Date) && !(v instanceof Map) && !(v instanceof Set))
        return Object.values(v as Record<string, unknown>).every(check);
      return false;
    };
    return z.custom(check);
  }))
